DROP TABLE IF EXISTS `attendance_records`;
CREATE TABLE `attendance_records`  (
  `id` int NOT NULL AUTO_INCREMENT,
  `personnel_id` int NOT NULL COMMENT '人员ID（关联personnel表）',
  `check_time` datetime NOT NULL COMMENT '打卡时间',
  `type` enum('in','out') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '类型：in进场/out离场',
  `source` enum('card','face','gps','manual') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT 'card' COMMENT '打卡方式',
  `remark` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '备注',
  `created_at` datetime NULL DEFAULT CURRENT_TIMESTAMP,
  `branch_id` int NULL DEFAULT NULL COMMENT '分公司ID',
  `project_id` int NULL DEFAULT NULL COMMENT '项目ID',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_personnel_time`(`personnel_id` ASC, `check_time` ASC) USING BTREE,
  INDEX `idx_date`(`check_time` ASC) USING BTREE,
  INDEX `idx_type`(`type` ASC) USING BTREE,
  CONSTRAINT `fk_attendance_personnel` FOREIGN KEY (`personnel_id`) REFERENCES `personnel` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 7675 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '考勤记录表' ROW_FORMAT = Dynamic;

