DROP TABLE IF EXISTS `devices`;
CREATE TABLE `devices`  (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '设备ID',
  `branch_id` int NULL DEFAULT NULL COMMENT '所属分公司ID',
  `project_id` int NULL DEFAULT NULL COMMENT '所属项目ID',
  `device_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '设备编号',
  `device_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '设备名称',
  `device_type` enum('rtk','uwb','gps_tag','gps_band','smart_helmet','bullet_camera','dome_camera','drone','body_camera','gateway') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '设备类型',
  `device_model` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '设备型号',
  `manufacturer` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '生产厂商',
  `serial_number` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '机器码/序列号',
  `is_online` tinyint(1) NULL DEFAULT 0,
  `is_fault` tinyint(1) NULL DEFAULT 0,
  `last_lat` decimal(10, 6) NULL DEFAULT NULL COMMENT '最后纬度',
  `last_lng` decimal(10, 6) NULL DEFAULT NULL COMMENT '最后经度',
  `install_location` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '安装位置',
  `enabled_date` date NULL DEFAULT NULL COMMENT '启用时间',
