-- ----------------------------
-- Table structure for electronic_fences
-- ----------------------------
DROP TABLE IF EXISTS `electronic_fences`;
CREATE TABLE `electronic_fences`  (
  `id` int NOT NULL AUTO_INCREMENT,
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '围栏名字',
  `project_region_id` int NULL DEFAULT NULL COMMENT '所属项目区域ID',
  `shape` enum('POLYGON','CIRCLE') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '围栏形状: polygon, circle',
  `behavior` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '管控类型: No Entry (禁入), No Exit (禁出)',
  `coordinates_json` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '坐标JSON: 多边形为点数组, 圆形为圆心坐标',
  `radius` float NULL DEFAULT NULL COMMENT '半径(米), 仅圆形围栏有效',
  `effective_time` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '生效时间,格式如5.00-23.00',
  `worker_count` int NULL DEFAULT NULL COMMENT '违规人数 (禁入时为区内人数，禁出时为区外人数)',
  `remark` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '围栏备注',
  `alarm_type` enum('HIGH','MEDIUM','LOW') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '报警类型',
  `is_active` int NULL DEFAULT NULL COMMENT '是否启用 1-启用 0-禁用',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `project_region_id`(`project_region_id` ASC) USING BTREE,
  INDEX `ix_electronic_fences_id`(`id` ASC) USING BTREE,
  INDEX `ix_electronic_fences_name`(`name` ASC) USING BTREE,
  CONSTRAINT `electronic_fences_ibfk_1` FOREIGN KEY (`project_region_id`) REFERENCES `project_regions` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci ROW_FORMAT = Dynamic;

