-- Records of electronic_fences
-- ----------------------------

-- ----------------------------
-- Table structure for fences
-- ----------------------------
DROP TABLE IF EXISTS `fences`;
CREATE TABLE `fences`  (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '围栏ID',
  `fence_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '围栏编号（业务唯一标识）',
  `branch_id` int NOT NULL COMMENT '所属分公司ID',
  `project_id` int NOT NULL COMMENT '所属项目ID',
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '围栏名称',
  `type` enum('circle','polygon') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '圆形/多边形',
  `behavior` enum('entry','exit','both') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '禁入/禁出/双向',
  `severity` enum('high','medium','low') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '围栏等级',
  `center_lat` decimal(10, 6) NULL DEFAULT NULL COMMENT '圆心纬度',
  `center_lng` decimal(10, 6) NULL DEFAULT NULL COMMENT '圆心经度',
  `radius` int NULL DEFAULT NULL COMMENT '半径(米)',
  `points` json NULL COMMENT '顶点坐标 [[lat,lng],...]',
  `start_time` datetime NOT NULL COMMENT '生效开始时间',
  `end_time` datetime NOT NULL COMMENT '生效结束时间',
  `status` enum('active','scheduled','expired','disabled') CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT 'scheduled' COMMENT '生效中/预约中/已过期/已禁用',
  `bound_device_ids` json NULL COMMENT '绑定的定位设备ID列表',
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT '描述',
  `created_at` datetime NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `idx_fence_code`(`fence_code` ASC) USING BTREE,
  INDEX `idx_branch_project`(`branch_id` ASC, `project_id` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE,
  INDEX `idx_time_range`(`start_time` ASC, `end_time` ASC) USING BTREE,
  INDEX `project_id`(`project_id` ASC) USING BTREE,
  CONSTRAINT `fences_ibfk_1` FOREIGN KEY (`branch_id`) REFERENCES `branches` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT,
  CONSTRAINT `fences_ibfk_2` FOREIGN KEY (`project_id`) REFERENCES `projects` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '电子围栏表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of fences
