CREATE TABLE `teams`  (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '作业队ID',
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '作业队名称',
  `branch_id` int NOT NULL COMMENT '所属分公司ID',
  `project_id` int NULL DEFAULT NULL COMMENT '所属项目ID',
  `leader` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '队长',
