-- ----------------------------
-- Table structure for video_devices
-- ----------------------------
DROP TABLE IF EXISTS `video_devices`;
CREATE TABLE `video_devices`  (
  `id` int NOT NULL AUTO_INCREMENT,
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '摄像头名称',
  `ip_address` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '设备IP地址',
  `port` int NULL DEFAULT NULL COMMENT '服务端口',
  `username` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '登录用户名',
  `password` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '登录密码',
  `stream_url` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '原始流地址 (RTSP/HLS/FLV)',
  `rtsp_url` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '摄像头RTSP地址',
  `latitude` float NULL DEFAULT NULL COMMENT '纬度 (GCJ-02)',
  `longitude` float NULL DEFAULT NULL COMMENT '经度 (GCJ-02)',
  `status` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '设备状态: online, offline',
  `remark` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '备注信息',
  `is_active` int NULL DEFAULT NULL COMMENT '是否启用 1-启用 0-禁用',
  `stream_protocol` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `platform_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `access_source` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
