  `device_serial` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `channel_no` int NULL DEFAULT NULL,
  `supports_ptz` int NOT NULL DEFAULT 1,
  `supports_preset` int NOT NULL DEFAULT 1,
  `supports_cruise` int NOT NULL DEFAULT 1,
  `supports_zoom` int NOT NULL DEFAULT 1,
  `supports_focus` int NOT NULL DEFAULT 0,
  `branch_id` int NULL DEFAULT NULL,
  `project_id` int NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `ix_video_devices_name`(`name` ASC) USING BTREE,
  INDEX `ix_video_devices_id`(`id` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1409 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci ROW_FORMAT = Dynamic;

