-- ----------------------------
-- View structure for v_personnel_stats
-- ----------------------------
DROP VIEW IF EXISTS `v_personnel_stats`;
CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `v_personnel_stats` AS select `personnel`.`branch_id` AS `branch_id`,`personnel`.`project_id` AS `project_id`,`personnel`.`role` AS `role`,count(0) AS `count` from `personnel` group by `personnel`.`branch_id`,`personnel`.`project_id`,`personnel`.`role`;

-- ----------------------------
-- View structure for v_today_attendance
-- ----------------------------
DROP VIEW IF EXISTS `v_today_attendance`;
CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `v_today_attendance` AS select `attendance_records`.`branch_id` AS `branch_id`,`attendance_records`.`project_id` AS `project_id`,count((case when (`attendance_records`.`checkin_time` is not null) then 1 end)) AS `today_in`,count((case when (`attendance_records`.`checkout_time` is not null) then 1 end)) AS `today_out` from `attendance_records` where (`attendance_records`.`date` = curdate()) group by `attendance_records`.`branch_id`,`attendance_records`.`project_id`;

-- ----------------------------
-- Procedure structure for bind_devices_worker
-- ----------------------------
DROP PROCEDURE IF EXISTS `bind_devices_worker`;
delimiter ;;
CREATE PROCEDURE `bind_devices_worker`()
BEGIN
    DECLARE done INT DEFAULT FALSE;
    DECLARE dev_id INT;
    DECLARE rand_person_id INT;
    
    -- 游标：所有未绑定的定位设备
    DECLARE cur CURSOR FOR 
        SELECT id FROM devices 
        WHERE device_type IN ('rtk', 'uwb', 'gps_tag', 'gps_band', 'smart_helmet')
        AND holder_id IS NULL;
    
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = TRUE;
    
    OPEN cur;
    
    read_loop: LOOP
        FETCH cur INTO dev_id;
        IF done THEN
            LEAVE read_loop;
        END IF;
        
        -- 随机获取一个工人ID
        SELECT id INTO rand_person_id FROM personnel 
        WHERE identity_level = 'worker' 
        ORDER BY RAND() LIMIT 1;
        
        -- 更新这条设备
        UPDATE devices SET holder_id = rand_person_id WHERE id = dev_id;
        
    END LOOP;
    
    CLOSE cur;
END
;;
delimiter ;

SET FOREIGN_KEY_CHECKS = 1;
